#include <stdio.h>
#include <unistd.h>

int main() {
 // Make a system call to create a new process
 pid_t process_id = fork();
 if (process_id == 0) {
 // Child process
 printf('Hello from child process');
 } else {
 // Parent process
 printf('Hello from parent process');
 }
 return 0;
}
